+                cachedExtract.source === 'page'
+                  ? 'readability (content script)'
+                  : (cachedExtract.diagnostics?.strategy ?? null),
+              markdownProvider: cachedExtract.diagnostics?.markdown?.used
+                ? (cachedExtract.diagnostics?.markdown?.provider ?? 'unknown')
